@module coordinator  src=coordinator.lua  loc=296  sha=4a6bfb0  mode=chunk
@deps cm, cmgr, gui

# Invariants & contracts
  @invariant  owns the active tracker take; polls REAPER's selection each frame while tracker page is active (sticky on no-item or non-MIDI)
  @invariant  no teardown path â€” quit() sets a flag that stops scheduling further defers; REAPER reclaims state on script unload
  @invariant  errors inside the defer loop surface through the same xpcall frame because each iteration reschedules itself
  @contract  returns early (no dispatch) when state.suppressKbd or not state.acceptCmds
  @contract  state.pageSuppressed shrinks the walk to the root keymap only â€” body-region editors (swing, tuning) suppress page bindings without shadowing globals like playPause/quit
  @contract  first-hit wins across the keychain; a command returning false declines and releases the key (clearing commandHeld) so the page char queue sees it
  @contract  while cmgr:isPrefixActive(), digits and '/' are captured (no dispatch); Esc cancels; any other key freezes the prefix and falls through to the keychain walk so commands can consumePrefix()

# Shapes
  @shape  dispatchResult = { consumed: bool, commandHeld: bool }
  @shape  page = { renderToolbarBits(ctx), renderBody(ctx,w,h,dispatch), renderStatusBar(ctx), bind(...), unbind(), [renderFloating(ctx)] }

# Imports
  @require util = 'util'  @ 7
  @require ImGui = 'imgui'  @ 14

# Constructed sub-instances
  @construct chrome = util.instantiate('chrome')  @ 19

# Private state
  @state ctx, uiFont = gui.ctx, gui.uiFont  @ 17
  @state CHROME_PAD_X, CHROME_PAD_Y = 8, 4  @ 21
  @state pages, active = {}, nil  @ 23
  @state quitting = false  @ 24
  @state samplerTrack = nil  @ 26
      @contract  owns the active sampler track â€” the picker on samplePage delegates here, and first sample-page activation seeds the default from pages.sample:listTracks()
  @state currentTake = nil  @ 28
      @contract  owns currentTake â€” refreshTakeFromReaper polls GetSelectedMediaItemâ†’GetActiveTakeâ†’TakeIsMIDI, mutates currentTake only on a real MIDI take that differs (sticky on nothing-selected or non-MIDI), and returns true so the caller can rebind
  @state lastTakeHash = nil  @ 30
      @contract  external-mutation watcher â€” captured at end of every tracker-active frame; top-of-tick diff triggers tp:reloadFromReaper. Cleared on take swap (bind path is the reload). Nil disables the diff check (one-frame grace after swap/first activation).
  @state coord = {}  @ 245
      @contract  pages must be registered via coord:register(name,page); first registered becomes active

# Private functions
  -- Keyboard router
  @fn handlePrefixCapture(cmgr, ctx)  @ 38
      -- Capture digits and '/' into the prefix buffer; Esc cancels. Returns
      -- 'consumed' if a prefix-accumulating key fired this frame; 'fall' to
      -- finishPrefix and let the normal keychain walk handle this key; nil if
      -- prefix mode is inactive.
  @fn dispatchKeys(state, cmgr, ctx)  @ 62
  -- Coordinator
  @fn refreshTakeFromReaper()  @ 94
  @fn takeMidiHash()  @ 104
  @fn tick()  @ 112
      @contract  tick() runs once per frame before the page draws; setPrefix is republished only when the project path changes (one mailbox cell shared across instances)
      @contract  tracker-active branch â€” take swap takes priority (clears the watcher so the post-bind end-of-frame capture is the new baseline); otherwise a hash diff signals an external mutation (REAPER Ctrl-Z, external script) and we reload the bound take
  @fn drawSwitcher()  @ 128
  @fn dispatch(state)  @ 144
  @fn frame()  @ 146

# Public API (coord:*)
  @api coord:register(name, page)  @ 247
  @api coord:setActive(name)  @ 253
      @contract  setActive(name) is a no-op when name == active; otherwise unbinds the outgoing page, swaps cmgr scope, and binds the incoming page (trackerâ†’currentTake, sampleâ†’samplerTrack)
  @api coord:setSamplerTrack(t)  @ 274
      @contract  stores the active sampler track and re-binds the sample page if currently active; safe to call before sample page is registered (state stashes; bind happens on next activation)
  @api coord:togglePage()  @ 281
  @api coord:reloadAfterExternalMutation()  @ 286
      @contract  invoke after firing a REAPER action that mutates the bound take from inside a frame (Ctrl-Z, Ctrl-Shift-Z). The watcher's end-of-frame baseline would otherwise absorb the mutation; this reloads now so tm/vm stay coherent with the take.
